extern int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float* intg,float* lastE);
extern float kiln_profile_setpoint(unsigned long elapsed_s,const float* temps,const unsigned long* durations,int n_seg);

const int SSR[3]={9,10,11},TC[3]={A0,A1,A2};
const float KP=1.8f,KI=0.04f,KD=2.0f,TEMP_MAX=1650.0f;
float intg[3]={0},lastE[3]={0};

const float PROF_T[]={25,600,600,1580,1580,25,25};
const unsigned long PROF_D[]={3600,3600,7200,7200,10800,3600,0};
const int N_SEG=7;
unsigned long start_ms=0;

// === TC Array ===
void tc_init(){for(int i=0;i<3;i++)pinMode(TC[i],INPUT);}
float tc_read(int z){return analogRead(TC[z])*3.0f/1023.0f*200.0f;}

// === SSR Array ===
void ssr_init(){for(int i=0;i<3;i++){pinMode(SSR[i],OUTPUT);analogWrite(SSR[i],0);}}
void ssr_set(int z,int p){analogWrite(SSR[z],constrain(p,0,255));}
void ssr_cutall(){for(int i=0;i<3;i++)analogWrite(SSR[i],0);}

// === Profile Scheduler ===
float get_setpoint(){return kiln_profile_setpoint((millis()-start_ms)/1000UL,PROF_T,PROF_D,N_SEG);}

// === Fault Handler ===
bool fault_check(float* temps){for(int i=0;i<3;i++){if(temps[i]>TEMP_MAX||temps[i]<0){ssr_cutall();Serial.print("FAULT:TC");Serial.println(i);return true;}}return false;}

// === RS232 Logger ===
void logger_write(float sp,float* t,int* p){
  Serial.print(millis()/1000);Serial.print(',');Serial.print(sp,0);
  for(int i=0;i<3;i++){Serial.print(',');Serial.print(t[i],1);}
  for(int i=0;i<3;i++){Serial.print(',');Serial.print(p[i]);}
  Serial.println();}

void setup(){
  Serial.begin(9600);
  tc_init();ssr_init();
  start_ms=millis();
  Serial.println("t,sp,T1,T2,T3,P1,P2,P3");
}

unsigned long lastMs=0;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<0.5f)return;lastMs=now;
  float temps[3];for(int i=0;i<3;i++)temps[i]=tc_read(i);
  if(fault_check(temps))return;
  float sp=get_setpoint();
  int pwms[3];
  for(int i=0;i<3;i++){pwms[i]=pid_heater_control(sp,temps[i],dt,KP,KI,KD,&intg[i],&lastE[i]);ssr_set(i,pwms[i]);}
  if((int)(now/1000)%10==0)logger_write(sp,temps,pwms);
}
